const webhookData = $('When Data Posted to Webhook').first().json.body;
const phoneData = $input.first().json;

const fullName = webhookData["Full name"] || "";
const email = webhookData["Email"] || "";
const companyName = webhookData["Company name"] || "";
const companyDomain = webhookData["Company domain"] || "";

const phone = phoneData.intl_format || "Not Found";
const phoneValid = phoneData.valid || false;

return [{
  json: {
    full_name: fullName,
    email: email,
    company: companyName,
    domain: companyDomain,
    phone: phone,
    phone_valid: phoneValid,
    country_code: phoneData.country_code || "",
    line_type: phoneData.line_type || "",
    slack_notified: "Yes",
    status: phoneValid ? "Contacted" : "No Phone Found",
    slack_message: `🔥 *New Lead Alert!*\n*Name:* ${fullName}\n*Company:* ${companyName}\n*Email:* ${email}\n*Domain:* ${companyDomain}\n*Phone:* ${phone}\n\nCall them NOW! ☎️`
  }
}];
